"""Text conversion functions."""
from .models import TextFormat, TextResult


# Legacy API — migrate to return Result objects
def convert_text(input_str, to_format):
    """Convert text to the specified format.

    Args:
        input_str: The input string to convert.
        to_format: Target format as a string ("upper", "lower", "title", "plain").

    Returns:
        The converted string.
    """
    if to_format == "upper":
        return input_str.upper()
    elif to_format == "lower":
        return input_str.lower()
    elif to_format == "title":
        return input_str.title()
    else:
        return input_str


# Modern API — do not touch
def transform_text(input_str, output_format=TextFormat.PLAIN):
    """Transform text using the modern API.

    Args:
        input_str: The input string to transform.
        output_format: Target format as a TextFormat enum.

    Returns:
        A TextResult with original, converted, and format info.
    """
    if output_format == TextFormat.UPPER:
        converted = input_str.upper()
    elif output_format == TextFormat.LOWER:
        converted = input_str.lower()
    elif output_format == TextFormat.TITLE:
        converted = input_str.title()
    else:
        converted = input_str
    return TextResult(
        original=input_str,
        converted=converted,
        format_applied=output_format.value,
    )
